/// Case lookup binds the fixture name to the registry array and yields
/// exactly eight cases.
#[test]
fn rbtdto_cases_registered() {
    let fix = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_ONBOARDING_SEQUENCE)
        .expect("onboarding-sequence is registered");
