        .expect("inscribe case present");
    let kludge_tadmor_idx = names
        .iter()
        .position(|n| n.contains("rbtdro_onboarding_kludge_tadmor"))
        .expect("kludge-tadmor case present");
    let kludge_ccyolo_idx = names
